initiateMfa = async (ctx: Context<Env>, user: UserModel) => {
  // If the user does not have MFA enabled, do nothing
  if (!user.mfaRequired) return null;

  const timespan = new TimeSpan(10, 'm');

  // Generate token and store hashed
  const newToken = nanoid(40);
  const hashedToken = encodeLowerCased(newToken);

  // Generate a new random token and insert it
  await db
    .insert(tokensTable)
    .values({
      secret: hashedToken,
      type: 'confirm-mfa',
      userId: user.id,
      email: user.email,
      createdBy: user.id,
      expiresAt: createDate(timespan), // token expires in 10 minutes
    })
    .returning({ secret: tokensTable.secret });

  // Set a temporary auth cookie to track confirm MFA session
  await setAuthCookie(ctx, 'confirm-mfa', newToken, timespan);

  // Return the path to redirect the user to MFA authentication page
  return '/auth/mfa';
}

async function sendNotificationToSubscriber<T extends CursoredSubscriber>(
  subscriber: T,
  event: ActivityEvent,
  notification: StreamNotification,
  transformNotification?: (notification: StreamNotification, subscriber: T) => StreamNotification,
  preSerialized?: string,
): Promise<void> {
  if (preSerialized) {
    await writeChangeRaw(subscriber.stream, event.id, preSerialized);
  } else {
    const final = transformNotification ? transformNotification(notification, subscriber) : notification;
    await writeChange(subscriber.stream, event.id, final);
  }

  logEvent(null, 'debug', 'SSE notification sent', {
    subscriberId: subscriber.id,
    activityId: event.id,
    entityType: event.entityType,
    action: event.action,
  });

  subscriber.cursor = event.id;
}

async function getPendingMembershipsOp(ctx: AuthContext, input: GetPendingMembershipsInput) {
  const organization = ctx.var.organization;

  const { entityId, entityType, sort, order, offset, limit } = input;
  const { entity } = await getValidContextEntity(ctx, entityId, entityType, 'read');

  const { rawItems, total } = await getPendingMembershipsList(ctx, {
    organizationId: organization.id,
    entityId: entity.id,
    sort,
    order,
    offset,
    limit,
  });

  const items = await withAuditUsers(ctx, rawItems);

  return { items, total };
}

canPerEntityType = (
  ctx: AuthContext,
  action: Exclude<EntityActionType, 'create'>,
  entity: SubjectForPermission,
) => {
  const isSystemAdmin = ctx.var.isSystemAdmin;
  const memberships = ctx.var.memberships;

  const { entityType } = entity;

  // Enforce that all ancestor context IDs are explicitly provided (null = intentional, undefined = missing)
  validateAncestorScope(entity);

  const { isAllowed } = checkPermission(memberships, action, entity, { isSystemAdmin });

  if (!isAllowed) {
    throw new AppError(403, 'forbidden', 'warn', { entityType, meta: { action } });
  }
}

function validateSqlIdentifier(identifier: string, type: string): string {
  if (!identifier || typeof identifier !== "string") {
    throw new ApiException(`Invalid ${type} name: must be a non-empty string`);
  }

  if (!SQL_IDENTIFIER_REGEX.test(identifier)) {
    throw new ApiException(
      `Invalid ${type} name "${identifier}": must start with a letter or underscore and contain only alphanumeric characters and underscores`,
    );
  }

  // Additional length check to prevent excessively long identifiers
  if (identifier.length > 128) {
    throw new ApiException(`Invalid ${type} name "${identifier}": exceeds maximum length of 128 characters`);
  }

  return identifier;
}

parseAndValidate = async <T extends ClassConstructor<any>>(
  dto: T,
  obj: object,
  options: ClassTransformOptions
): Promise<
  { success: false; errors: ValidationError[] } | { success: true; output: InstanceType<T> }
> => {
  // tranform the literal object to class object
  const objInstance = plainToClass(dto, obj, options)
  // validating and check the errors, throw the errors if exist

  const errors = await validate(objInstance)
  // errors is an array of validation errors
  if (errors.length > 0) {
    return {
      success: false,
      errors,
    }
  }

  return { success: true, output: objInstance as InstanceType<T> }
}

async function isValidJwtSignature(token: DecodedToken, keys: Record<string, CryptoKey>) {
  const encoder = new TextEncoder()
  const data = encoder.encode([token.raw.header, token.raw.payload].join('.'))

  const signature = token.signature

  // RFC 7515 §4.1.4: Use kid to select the verification key when present
  if (token.header.kid) {
    const key = keys[token.header.kid]
    if (key) {
      return validateSingleKey(key, signature, data)
    }
  }

  // Fall back to trying all keys only when kid is absent
  if (!token.header.kid) {
    for (const key of Object.values(keys)) {
      const isValid = await validateSingleKey(key, signature, data)

      if (isValid) {
        return true
      }
    }
  }

  return false
}

async process(
  processor: (fieldName: string, file: File) => Promise<void>,
): Promise<void> {
  if (this.processed) {
    throw new Error('Request already processed');
  }

  this.processed = true;
  const parts = getParts(this.req, this.options);

  try {
    for await (const [fieldName, part] of Object.entries(parts)) {
      // Handle array of files (for multiple file uploads with same field name)
      if (Array.isArray(part) && part.every((item) => item instanceof File)) {
        for (const file of part) {
          await processor(fieldName, file);
        }
        continue;
      }

      if (!(part instanceof File)) {
        this.body[fieldName] = part;
        continue;
      }

      await processor(fieldName, part);
    }
  } catch (error) {
    await this.cleanup(true);
    throw error;
  }
}

private getClient(key: string): Client {
  // If we already have a client for that key in the `current` map, return it.
  const currentKey = this.current.get(key);
  if (currentKey) return currentKey;

  let client: Client;
  const previousKey = this.previous.get(key);
  if (previousKey) {
    // If it's in the `previous` map, take it out
    client = previousKey;
    this.previous.delete(key);
  } else {
    // Finally, if we don't have an existing entry for this client, create a new one
    client = { totalHits: 0, resetTime: new Date() };
    this.resetClient(client);
  }

  // Make sure the client is bumped into the `current` map, and return it.
  this.current.set(key, client);
  return client;
}

async function executeHandler(code: string, context: HandlerContext): Promise<HandlerExecutionResult> {
  // Create a function that executes the handler code with the context
  // Using Function constructor to create a sandboxed environment
  // The code is wrapped in a function body that returns the result
  const handlerFunction = new Function(
    'store',
    'faker',
    'req',
    'res',
    `
    ${code}
  `,
  )
  const result = handlerFunction(context.store, context.faker, context.req, context.res)

  // If the result is a Promise, await it
  if (result instanceof Promise) {
    return { result: await result }
  }

  return { result }
}

async function executeSeed(code: string, context: SeedContext): Promise<SeedExecutionResult> {
  // Create a function that executes the seed code with the context
  // Using Function constructor to create a sandboxed environment
  // The code is wrapped in a function body that returns the result
  const seedFunction = new Function(
    'store',
    'faker',
    'seed',
    'schema',
    `
    ${code}
  `,
  )

  // Execute the seed function with the context
  try {
    const result = seedFunction(context.store, context.faker, context.seed, context.schema)

    // If the result is a Promise, await it
    if (result instanceof Promise) {
      return { result: await result }
    }

    return { result }
  } catch (error) {
    // Re-throw to be caught by the caller
    throw error
  }
}

async function deleteGiteaIntegration(projectId: string) {
  const integration = await db.query.integrationTable.findFirst({
    where: and(
      eq(integrationTable.projectId, projectId),
      eq(integrationTable.type, "gitea"),
    ),
  });

  if (!integration) {
    throw new HTTPException(404, { message: "Gitea integration not found" });
  }

  await db
    .delete(integrationTable)
    .where(
      and(
        eq(integrationTable.projectId, projectId),
        eq(integrationTable.type, "gitea"),
      ),
    );

  return { success: true, message: "Gitea integration deleted" };
}

async function deleteGithubIntegration(projectId: string) {
  const existingIntegration = await db.query.integrationTable.findFirst({
    where: and(
      eq(integrationTable.projectId, projectId),
      eq(integrationTable.type, "github"),
    ),
  });

  if (!existingIntegration) {
    throw new HTTPException(404, { message: "GitHub integration not found" });
  }

  await db
    .delete(integrationTable)
    .where(
      and(
        eq(integrationTable.projectId, projectId),
        eq(integrationTable.type, "github"),
      ),
    );

  return { success: true, message: "GitHub integration deleted" };
}

async function getGithubIntegration(projectId: string) {
  const integration = await db.query.integrationTable.findFirst({
    where: and(
      eq(integrationTable.projectId, projectId),
      eq(integrationTable.type, "github"),
    ),
  });

  if (!integration) {
    return null;
  }

  const config = JSON.parse(integration.config) as GitHubConfig;

  return {
    id: integration.id,
    projectId: integration.projectId,
    repositoryOwner: config.repositoryOwner,
    repositoryName: config.repositoryName,
    installationId: config.installationId,
    branchPattern: config.branchPattern || defaultGitHubConfig.branchPattern,
    commentTaskLinkOnGitHubIssue: config.commentTaskLinkOnGitHubIssue !== false,
    isActive: integration.isActive,
    createdAt: integration.createdAt,
    updatedAt: integration.updatedAt,
  };
}

async function deleteWorkspaceRule(
  userId: string,
  workspaceId: string,
  emailAddress: string | null,
): Promise<NotificationPreferenceResponse> {
  await assertWorkspaceMembership(userId, workspaceId);

  const existing = await db.query.userNotificationWorkspaceRuleTable.findFirst({
    where: and(
      eq(userNotificationWorkspaceRuleTable.userId, userId),
      eq(userNotificationWorkspaceRuleTable.workspaceId, workspaceId),
    ),
  });

  if (!existing) {
    throw new HTTPException(404, {
      message: "Workspace notification rule not found",
    });
  }

  await db
    .delete(userNotificationWorkspaceRuleTable)
    .where(eq(userNotificationWorkspaceRuleTable.id, existing.id));

  return getNotificationPreferences(userId, emailAddress);
}

function parseTelegramIntegrationConfig(
  integration: Pick<TelegramIntegrationRecord, "config" | "id" | "projectId">,
): TelegramConfig {
  try {
    const parsed = v.parse(
      telegramConfigSchema,
      JSON.parse(integration.config),
    );
    return normalizeTelegramConfig(parsed);
  } catch (error) {
    console.error("Failed to parse Telegram integration config", {
      error,
      integrationId: integration.id,
      projectId: integration.projectId,
      sanitizedConfig: sanitizeTelegramConfigForLog(integration.config),
    });
    throw new HTTPException(500, {
      message: "Stored Telegram integration configuration is invalid",
    });
  }
}
